// Helper function to parse input string into a vector<int> and size.
// This function handles both "{...}" and "nullptr, X" formats.
std::pair<std::vector<int>, int> parseInput(const std::string& input_str) {
    std::vector<int> arr_vec;
    int size = 0;

    if (input_str.find("nullptr") != std::string::npos) {
        // Format: "nullptr, X"
        try {
            size = std::stoi(input_str.substr(input_str.find(',') + 1));
        } catch (const std::invalid_argument& e) {
            std::cerr << "Error parsing size for nullptr input: " << e.what() << std::endl;
            size = 0; // Default to 0 on error
        }
        return {arr_vec, size}; // arr_vec is empty, indicating nullptr
    }

    // Format: "{...}" or "{}" or ""
    std::string s = input_str;
    if (s.empty() || s == "{}") {
        return {arr_vec, 0};
    }

    // Remove brackets if present
    if (s.front() == '{' && s.back() == '}') {
        s = s.substr(1, s.length() - 2);
    }

    std::stringstream ss(s);
    std::string segment;
    while(std::getline(ss, segment, ',')) {
        try {
            arr_vec.push_back(std::stoi(segment));
        } catch (const std::invalid_argument& e) {
            std::cerr << "Warning: Invalid number format in input segment: '" << segment << "'" << std::endl;
        }
    }
    size = arr_vec.size();
    return {arr_vec, size};
}

